"use strict";(globalThis.webpackChunkregenx_docs=globalThis.webpackChunkregenx_docs||[]).push([[495],{5546:(e,a,o)=>{o.r(a),o.d(a,{assets:()=>d,contentTitle:()=>t,default:()=>p,frontMatter:()=>n,metadata:()=>s,toc:()=>c});const s=JSON.parse('{"id":"about","title":"Descubre RegenAg-x","description":"El demostrador de espacio de datos agroalimentarios para servicios de compartici\xf3n de datos soberanos e Inteligencia Artificial","source":"@site/docs/about.md","sourceDirName":".","slug":"/about/","permalink":"/regenag-x-docs.github.io/documentacion/about/","draft":false,"unlisted":false,"editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/docs/about.md","tags":[],"version":"current","frontMatter":{"slug":"/about/","title":"Descubre RegenAg-x","sidebar_label":"Sobre RegenAg-x"},"sidebar":"tutorialSidebar","next":{"title":"Modelo de gobernanza","permalink":"/regenag-x-docs.github.io/documentacion/governance"}}');var r=o(4848),i=o(8453);const n={slug:"/about/",title:"Descubre RegenAg-x",sidebar_label:"Sobre RegenAg-x"},t="Descubre RegenAg-x",d={},c=[{value:"El demostrador de espacio de datos agroalimentarios para servicios de compartici\xf3n de datos soberanos e Inteligencia Artificial",id:"el-demostrador-de-espacio-de-datos-agroalimentarios-para-servicios-de-compartici\xf3n-de-datos-soberanos-e-inteligencia-artificial",level:2}];function l(e){const a={a:"a",h1:"h1",h2:"h2",header:"header",li:"li",ol:"ol",p:"p",...(0,i.R)(),...e.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(a.header,{children:(0,r.jsx)(a.h1,{id:"descubre-regenag-x",children:"Descubre RegenAg-x"})}),"\n",(0,r.jsx)(a.h2,{id:"el-demostrador-de-espacio-de-datos-agroalimentarios-para-servicios-de-compartici\xf3n-de-datos-soberanos-e-inteligencia-artificial",children:"El demostrador de espacio de datos agroalimentarios para servicios de compartici\xf3n de datos soberanos e Inteligencia Artificial"}),"\n",(0,r.jsx)(a.p,{children:"Este demostrador se plantea con una importante carga de personal para el asesoramiento y desarrollo de casos de uso para apoyar a los participantes que han mostrado su inter\xe9s pero no han tenido la oportunidad o la capacidad de presentar sus casos de uso por separado para esta convocatoria."}),"\n",(0,r.jsx)(a.p,{children:"Adem\xe1s, implica una amplia y diversa red de participantes interesados en formar parte del demostrador, representando ampliamente a los diferentes tipos de actores involucrados en el sector agroalimentario, especialmente la parte productiva ya que se quiere mantener una estrecha colaboraci\xf3n con el futuro Espacio Com\xfan Europeo de Datos Agr\xedcolas (CEADS), que se centra en este sector."}),"\n",(0,r.jsx)(a.p,{children:"El espacio de datos se regir\xe1 por un c\xf3digo de gobernanza expl\xedcito, asegurando una mayor transparencia, con especial atenci\xf3n a preservar la equidad de los participantes y su no discriminaci\xf3n, as\xed como su sostenibilidad."}),"\n",(0,r.jsx)(a.p,{children:"Los participantes desempe\xf1ar\xe1n diferentes roles, incluidos productores y consumidores de datos, consumidores de datos y proveedores de servicios, proveedores de servicios inform\xe1ticos y operadores de servicios ecosist\xe9micos del espacio de datos. Los proveedores de computaci\xf3n tambi\xe9n actuar\xe1n como intermediarios de datos, en particular el papel de tercero de confianza donde se procesa la informaci\xf3n."}),"\n",(0,r.jsx)(a.p,{children:'La intermediaci\xf3n para el procesamiento de datos se realizar\xe1 utilizando tecnolog\xeda de computaci\xf3n a datos, de modo que se pueda garantizar la soberan\xeda de los datos por dise\xf1o. Este servicio se contratar\xe1 con un proveedor de "salas de datos" en la nube, que proporcionar\xe1 el entorno de alto rendimiento para realizar la computaci\xf3n de datos, incluidos los procesos de Inteligencia Artificial.'}),"\n",(0,r.jsx)(a.p,{children:"El c\xf3digo de gobernanza del espacio de datos permitir\xe1 la promulgaci\xf3n de pol\xedticas de acceso y uso de recursos. Tambi\xe9n definir\xe1 mecanismos para crear incentivos para compartir datos y servicios, as\xed como para la sostenibilidad del propio espacio de datos. Estos mecanismos se basar\xe1n en un Euro electr\xf3nico que utilice tecnolog\xedas de registro distribuido, sin valor econ\xf3mico real durante la fase de demostraci\xf3n, pero que permitir\xe1 a todos los participantes explorar posibles econom\xedas de datos para la sostenibilidad futura del espacio de datos."}),"\n",(0,r.jsx)(a.p,{children:"La infraestructura de registro distribuido utilizada para la monetizaci\xf3n del espacio de datos tambi\xe9n permitir\xe1 el seguimiento de las transacciones del espacio de datos y su auditor\xeda. A partir de este registro se desplegar\xe1n tambi\xe9n mecanismos de resoluci\xf3n de conflictos estipulados en el propio c\xf3digo de gobernanza."}),"\n",(0,r.jsx)(a.p,{children:"El demostrador se basar\xe1 en los principios FAIR para facilitar la b\xfasqueda y acceso a los recursos compartidos a trav\xe9s del mismo, y hacerlos interoperables y reutilizables. Para ello, todos los recursos contar\xe1n con descripciones de sus caracter\xedsticas y condiciones de uso, utilizando tecnolog\xedas sem\xe1nticas que faciliten su procesamiento autom\xe1tico."}),"\n",(0,r.jsxs)(a.p,{children:["El espacio de datos albergar\xe1 tanto recursos propietarios (datos y servicios para su procesamiento) compartidos bajo condiciones de uso, como fuentes de datos abiertos, especialmente conjuntos de datos de alto valor y de gran relevancia en el sector agroalimentario ",(0,r.jsx)(a.a,{href:"https://doi.org/10.1016/j.compag.2024.108775",children:"(Chamorro-Padial, Garc\xeda, Gil, 2024)"}),". Especialmente fuentes de datos abiertos relevantes para el sector agroalimentario como los generados por los programas Galileo y Copernicus."]}),"\n",(0,r.jsx)(a.p,{children:"Los servicios compartidos a trav\xe9s del espacio de datos incluir\xe1n algoritmos que implementen mecanismos para validar el nivel de calidad de los datos aportados por los participantes. Estos algoritmos, por ejemplo, el An\xe1lisis Exploratorio de Datos (EDA), pueden aplicarse a los datos para calcular m\xe9tricas de calidad asegurando su soberan\xeda. Esto ser\xe1 debido al propio dise\xf1o del espacio de datos, que implementa mecanismos de computaci\xf3n a datos que pueden asegurar que el propietario no pierda el control sobre los mismos."}),"\n",(0,r.jsx)(a.p,{children:"Para facilitar la interoperabilidad y reutilizaci\xf3n de datos y servicios, el espacio de datos integrar\xe1 servicios de transformaci\xf3n de datos en representaciones basadas en tecnolog\xedas sem\xe1nticas que har\xe1n referencia a formalizaciones como ontolog\xedas de vocabularios comunes del dominio agroalimentario."}),"\n",(0,r.jsx)(a.p,{children:"El demostrador propuesto se desplegar\xe1 utilizando los componentes del ecosistema de espacio de datos Pontus-X. Estos componentes son de c\xf3digo abierto y cualquier nuevo desarrollo o mejora que se realice durante el proyecto se compartir\xe1 de la misma manera que en los repositorios de c\xf3digo abierto de Pontus-X."}),"\n",(0,r.jsx)(a.p,{children:"Se contratar\xe1n los servicios de una empresa que proporcione los componentes de Pontus-X para facilitar la integraci\xf3n del demostrador con otros espacios de datos que ya est\xe1n en marcha en este ecosistema. Adem\xe1s, esta empresa proporcionar\xe1 los componentes de forma dedicada para la versi\xf3n de prueba del espacio de datos, que funcionar\xe1 de forma independiente. Estos componentes, tanto en su versi\xf3n compartida como dedicada, proporcionan las siguientes tecnolog\xedas:"}),"\n",(0,r.jsxs)(a.ol,{children:["\n",(0,r.jsx)(a.li,{children:'Tecnolog\xedas "Compute-to-data" para garantizar la privacidad y soberan\xeda de los datos por dise\xf1o, de modo que se pueda garantizar que los datos se procesen de manera protegida y confidencial. Tambi\xe9n permiten implementar el aprendizaje federado.'}),"\n",(0,r.jsx)(a.li,{children:'Mecanismos para compartir datos, pero tambi\xe9n servicios de procesamiento de datos, preferiblemente encapsulados como contenedores (Docker y Kubernetes) con todo su c\xf3digo y dependencias para facilitar su portabilidad y ejecuci\xf3n en el entorno "compute-to-data". Estos servicios incluyen herramientas avanzadas de anal\xedtica descriptiva, predictiva y prescriptiva.'}),"\n",(0,r.jsx)(a.li,{children:"Tecnolog\xedas de libro mayor distribuido que permiten trazar todas las transacciones realizadas en el ecosistema de espacios de datos, por ende m\xfaltiples espacios de datos conectados."}),"\n",(0,r.jsx)(a.li,{children:'Tecnolog\xedas de Smart Contract que permiten implementar los mecanismos de monetizaci\xf3n de datos, servicios y costos computacionales del mecanismo "compute-to-data". Libro mayor distribuido y contratos inteligentes basados en el est\xe1ndar EVM (Ethereum Virtual Machine). Facilitan la independencia de la soluci\xf3n tecnol\xf3gica subyacente, posibilitando su portabilidad y despliegue a trav\xe9s de diferentes infraestructuras.'}),"\n",(0,r.jsx)(a.li,{children:"Tecnolog\xedas de Monedero Digital para asegurar la soberan\xeda de los participantes y la autogesti\xf3n de atributos relacionados con su identidad."}),"\n"]})]})}function p(e={}){const{wrapper:a}={...(0,i.R)(),...e.components};return a?(0,r.jsx)(a,{...e,children:(0,r.jsx)(l,{...e})}):l(e)}},8453:(e,a,o)=>{o.d(a,{R:()=>n,x:()=>t});var s=o(6540);const r={},i=s.createContext(r);function n(e){const a=s.useContext(i);return s.useMemo(function(){return"function"==typeof e?e(a):{...a,...e}},[a,e])}function t(e){let a;return a=e.disableParentContext?"function"==typeof e.components?e.components(r):e.components||r:n(e.components),s.createElement(i.Provider,{value:a},e.children)}}}]);